class Solution {
    public int[] findFirstAndLastPositionOfElementInSortedArray(int[] data) {
        int[] result = new int[2];
        result[0] = findFirstPosition(data, 0, data.length - 1);
        result[1] = findLastPosition(data, 0, data.length - 1);
        return result;
    }
    private int findFirstPosition(int[] data, int left, int right) {
        int first = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (data[mid] == data[0]) {
                first = mid;
                right = mid - 1;
            }
            else if (data[mid] < data[0]) {
                left = mid + 1;
            }
            else {
                right = mid - 1;
            }
        }
        return first;
    }
    private int findLastPosition(int[] data, int left, int right) {
        int last = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (data[mid] == data[0]) {
                last = mid;
                left = mid + 1;
            }
            else if (data[mid] < data[0]) {
                left = mid + 1;
            }
            else {
                right = mid - 1;
            }
        }
        return last;
    }
}

