using namespace std;
class Solution {
    public:
    vector<int> findFirstAndLastPositionOfElementInSortedArray(const vector<int>& data, int target) {
        vector<int> result = {
            -1, -1
        }
        ;
        int left = 0, right = data.size() - 1;
        // Find the first position
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (data[mid] < target) {
                left = mid + 1;
            }
            else {
                right = mid - 1;
            }
        }
        if (left < data.size() && data[left] == target) {
            result[0] = left;
        }
        // Reset right and find the last position
        left = 0;
        right = data.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (data[mid] <= target) {
                left = mid + 1;
            }
            else {
                right = mid - 1;
            }
        }
        if (right >= 0 && data[right] == target) {
            result[1] = right;
        }
        return result;
    }
}
