            if (data[mid] == data[0]) {
                result = mid;
                right = mid - 1;
            } else if (data[mid] < data[0]) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return result;
    }

    private int FindLastPosition(int[] data, int left, int right) {
        int result = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (data[mid] == data[0]) {
                result = mid;
                left = mid + 1;
            } else if (data[mid] < data[0]) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return result;
    }
